import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function Register() {
  const { register } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: "", email: "", password: "", role: "faculty", department: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); setLoading(true);
    try {
      await register(form);
      navigate("/dashboard");
    } catch (err) {
      setError(err.response?.data?.detail || "Registration failed.");
    } finally {
      setLoading(false);
    }
  };

  const Field = ({ label, name, type = "text", placeholder, children }) => (
    <div>
      <label style={{ display: "block", fontSize: 11, fontFamily: "var(--mono)", color: "var(--text2)", marginBottom: 6, textTransform: "uppercase", letterSpacing: "0.08em" }}>
        {label}
      </label>
      {children || (
        <input
          type={type} required
          value={form[name]}
          onChange={e => setForm(f => ({ ...f, [name]: e.target.value }))}
          placeholder={placeholder}
        />
      )}
    </div>
  );

  return (
    <div style={{
      minHeight: "100vh", background: "var(--bg)",
      display: "flex", alignItems: "center", justifyContent: "center", padding: 24,
    }}>
      <div style={{
        position: "fixed", inset: 0, pointerEvents: "none",
        backgroundImage: "linear-gradient(var(--border) 1px, transparent 1px), linear-gradient(90deg, var(--border) 1px, transparent 1px)",
        backgroundSize: "40px 40px", opacity: 0.3,
      }} />

      <div className="fade-in" style={{ width: "100%", maxWidth: 460, position: "relative" }}>
        <div style={{ textAlign: "center", marginBottom: 32 }}>
          <div style={{
            display: "inline-flex", alignItems: "center", justifyContent: "center",
            width: 48, height: 48, background: "var(--accent)", borderRadius: 8,
            fontFamily: "var(--mono)", fontWeight: 700, fontSize: 18, marginBottom: 12,
          }}>FS</div>
          <h1 style={{ fontSize: 24, fontFamily: "var(--mono)", letterSpacing: 3 }}>FAILSAFE</h1>
        </div>

        <div className="card" style={{ padding: 32 }}>
          <h2 style={{ fontSize: 18, marginBottom: 24, fontFamily: "var(--mono)" }}>Create Account</h2>

          {error && (
            <div style={{
              background: "rgba(255,60,95,0.1)", border: "1px solid rgba(255,60,95,0.3)",
              borderRadius: 4, padding: "10px 14px", marginBottom: 20,
              color: "var(--danger)", fontSize: 13,
            }}>⚠ {error}</div>
          )}

          <form onSubmit={handleSubmit} style={{ display: "flex", flexDirection: "column", gap: 14 }}>
            <Field label="Full Name" name="name" placeholder="Enter Your Name" />
            <Field label="Email" name="email" type="email" placeholder="something@something.com" />
            <Field label="Password" name="password" type="password" placeholder="********" />
            <Field label="Department" name="department" placeholder="Computer Science" />

            <Field label="Role">
              <select
                value={form.role}
                onChange={e => setForm(f => ({ ...f, role: e.target.value }))}
              >
                <option value="faculty">Faculty</option>
                <option value="hod">Head of Department (HOD)</option>
                <option value="admin">Admin</option>
              </select>
            </Field>

            <button
              type="submit"
              className="btn btn-primary"
              disabled={loading}
              style={{ width: "100%", justifyContent: "center", padding: "13px 20px", marginTop: 6 }}
            >
              {loading ? "Creating account..." : "Create Account →"}
            </button>
          </form>

          <p style={{ marginTop: 20, textAlign: "center", color: "var(--text2)", fontSize: 13 }}>
            Already have an account?{" "}
            <Link to="/login" style={{ color: "var(--accent)", textDecoration: "none" }}>Login</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
